claim_dir.mkdir(parents=True, exist_ok=True)

for claim in all_claims:
    filename = id_to_filename[claim['id']]
    filepath = claim_dir / filename
    with open(filepath, 'w') as f:
        yaml.dump(claim, f, default_flow_style=False, sort_keys=False, allow_unicode=True)
    print(f"Wrote {filename}")

print(f"\nTotal: {len(all_claims)} claims written")
